const { getCurrentWeather, getForecast } = require('../src/weatherClient');
const axios = require('axios');

jest.mock('axios', () => ({ create: () => ({ get: jest.fn() }) }));

describe('weatherClient', () => {
  describe('getCurrentWeather', () => {
    it('returns formatted weather data', async () => {
      const mockResponse = { data: { main: { temp: 22.5, humidity: 65 }, weather: [{ description: 'clear sky', icon: '01d' }], name: 'London' } };
      require('axios').create().get.mockResolvedValue(mockResponse);
      const result = await getCurrentWeather('London');
      expect(result.name).toBe('London');
      expect(result.temp).toBe(22.5);
    });

    it('throws on city not found', async () => {
      require('axios').create().get.mockRejectedValue({ response: { status: 404 } });
      await expect(getCurrentWeather('FakeCity123')).rejects.toThrow();
    });
  });

  describe('getForecast', () => {
    it('returns 5 days of forecast data', async () => {
      const items = [];
      for (let i = 0; i < 5; i++) {
        const date = new Date(); date.setDate(date.getDate() + i);
        items.push({ dt_txt: `${date.toISOString().split('T')[0]} 12:00:00`, main: { temp_max: 20+i, temp_min: 10+i }, weather: [{ description: 'clear', icon: '01d' }] });
      }
      require('axios').create().get.mockResolvedValue({ data: { list: items } });
      const result = await getForecast('Tokyo');
      expect(result.length).toBe(5);
    });
  });
});

const request = require('supertest');
const express = require('express');
const weatherRoutes = require('../routes/weather');

const app = express();
app.use('/api/weather', weatherRoutes);

describe('Weather Routes', () => {
  it('GET /api/weather/:city returns weather data', async () => {
    const res = await request(app).get('/api/weather/London');
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('temp');
  });

  it('GET /api/weather/:city/forecast returns forecast', async () => {
    const res = await request(app).get('/api/weather/London/forecast');
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
  });

  it('returns 404 for unknown city', async () => {
    const res = await request(app).get('/api/weather/FakeCity123456');
    expect(res.status).toBe(404);
  });
});
